import { createWebHistory, createRouter } from "vue-router";
import Home from "./App.vue";
import DetailVue from "./views/DetailVue.vue";

const routes = [
    {
        path: "/",
        component: Home,
    },
    {
        path: "/detail",
        component: DetailVue,
    },
];

const router = createRouter({
    history: createWebHistory(),
    routes,
});

export default router;
